#include “STM32F10x.h”

//#include <stm32f103x6.h>

#define SampleNumber 100
// INIT functions ------------------------
void GPIOInit(void);
void gpioIntInit(void);
void spi1Init(void);
void timer2Init(void);
void GenaralSramSetting(void);
// TRANSMITE DATA functions ---------------
uint16_t RamReader(void);
void RamWriter(uint16_t d);
void DAC(uint16_t d);
uint16_t ADC (void);
//GLOBAL data -----------------------------
uint16_t Counter=0;
uint16_t address=0x0000;
uint8_t flag1=1;
//Main function -------------------------------
int main(){

GPIOInit();
gpioIntInit();
spi1Init();
timer2Init();
GenaralSramSetting();

while(1){
}
}
//GPIO AND GENERAL SETTING-------------------------------------------------
void GPIOInit(void){
RCC->APB2ENR = RCC_APB2ENR_IOPAEN | RCC_APB2ENR_IOPBEN ;
RCC->APB2RSTR |= RCC_APB2RSTR_IOPARST | RCC_APB2RSTR_IOPBRST;
RCC->APB2RSTR &= ~(RCC_APB2RSTR_IOPARST | RCC_APB2RSTR_IOPBRST);
GPIOA->CRL = 0xa4a42224 ; //a5, a7 : spi1, a1, a2, a3 : output (NCS)
GPIOA->ODR |= 0x00e ;
GPIOB->CRL = 0x22224444 ; //b1: push button
GPIOB->CRH = 0x22222222 ;

}
//--------------------------------------------------------------
void gpioIntInit(void){

RCC->APB2ENR |= 0x00000001 ;
AFIO->EXTICR[0] =0x0010; //interrupt from port B pin 1
EXTI->IMR = (1<<1); //PB1 unmasked
//EXTI->EMR = 0<<1; //no event
EXTI->FTSR = (1<<1); //falling edge interrupt
//EXTI->RTSR = 0<<1; //rising edge(no)
EXTI->PR = (1<<1); //clear pending interrupts
//EXTI->SWIER = 0<<1; //no software interrupt
NVIC_EnableIRQ(EXTI1_IRQn);//This line enables the interrupt request for EXTI1_IRQn.
//EXTI1 because interrupt is received through pin 1 og portB
}
//---------------------------------------------------------------
void EXTI1_IRQHandler(void){
EXTI->PR = (1<<1);//clear pending interrupts on PB1
EXTI->IMR = ~(1<<1);//PB1 is masked
flag1 = 0;
address = 0;
}

//---------------------------------------------------------------

//------------------------------------------------------------------
void timer2Init(void){
RCC->APB1RSTR |= RCC_APB1RSTR_TIM2RST;
RCC->APB1RSTR &= ~(RCC_APB1RSTR_TIM2RST);//reset the TIM2 register
RCC->APB1ENR |= RCC_APB1ENR_TIM2EN;//enable the TIM2 register
// 1 kHz–1ms---------------------------------------
//Ttimer=Tclockprescalor(autoreload+1)
TIM2->PSC = (40-1); //prescaler
TIM2->ARR = (200-1); //auto-reload
//---------------------------------------------

TIM2->DIER = 0x0001; // update interrupt enable
TIM2->CR1 = 0x0001; //enable timer

NVIC_EnableIRQ(TIM2_IRQn);
}
//---------------------------------------------------------------
void TIM2_IRQHandler(void){
TIM2->SR &= ~0x00000001; // This line clears the TIM2 interrupt flag.
// send data as normal satae ------
if(flag1==1){
DAC(RamReader());
}
//-----------------------------------
// recieve data after intrupt ------
else{
RamWriter(ADC());
Counter++;
if(Counter==SampleNumber){
flag1=1;
Counter=0;
address=0;
EXTI->IMR = (1<<1);
}
}
//-----------------------------------
}
// ----------------------------------------------------------
void GenaralSramSetting(void){//The GenaralSramSetting function initializes the external SRAM
GPIOB->ODR |= (0x0010);//PB4=1 --which deactivates the chip select signal for the external SRAM.
//This line of code ensures that the chip select signal is inactive before sending the write command to the SRAM.
GPIOB->ODR &= ~(0x0010);//PB4=0–which activates the chip select signal for the SRAM.
// This line of code is used to select the SRAM before sending any read or write commands to it.

SPI1->DR = 0x01;//WRSR 0000 0001 Write STATUS register //Write STATUS register// This line sets the data register of the SPI1 peripheral to 0x01, which corresponds to the command to write to the SRAM status register.
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY); // sr-> flags //This is a busy-wait loop that waits for the SPI peripheral to finish transmitting data before proceeding to the next line of code.

SPI1->DR = 0x40; //Sequential mode 0100_0000//This line sets the data register of the SPI1 peripheral to 0x40, which sets the sequential mode of the SRAM to 0x40. This corresponds to the mode in which the SRAM sends/receives a sequence of data bytes without requiring re-sending the address, which is useful in applications where large amounts of contiguous data are being read/written.
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY); // sr-> flags //This is another busy-wait loop that waits for the SPI peripheral to finish transmitting data before proceeding to the next line of code.
GPIOB->ODR |= (0x0010);//This line sets GPIO pin B4 high, which deactivates the chip select signal for the SRAM. This is necessary to complete the initialization of the SRAM and return it to its inactive state.
}
//-------------------------------------------------------------------------------------------
void spi1Init(void){
RCC->APB2RSTR |= RCC_APB2RSTR_SPI1RST;
RCC->APB2RSTR &= ~RCC_APB2RSTR_SPI1RST;
RCC->APB2ENR |= RCC_APB2ENR_SPI1EN;
// faal sazi clk

SPI1->CR1 = 0x0044; //0100_0100
// bit 6 : spi anable
// bit 2 : mster selection
SPI1->CR2 = 0x0004; // 0000 0100//configures the SPI1 peripheral to automatically control the NSS pin during data transmission/reception, allowing the microcontroller to use hardware management of the slave select signals rather than software management.


}
//---------------------------------------------------------------------
uint16_t ADC(void){ // meghdar motale shode ra barmigardanad
uint16_t a;
GPIOA->ODR &= ~(0x0002); // select ADC as slave
SPI1->DR = 0x06;//instructs the ADC to start the conversion process.
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR = 0x40;//This line of code sends a command to the ADC using the SPI1 interface to start an analog to digital conversion for a specific input channel.
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY); // 4 bit vazn bala
a=((SPI1->DR & 0x000f)<<8);
SPI1->DR = 0x00;
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY); // 8 bit vazn paeen
a |= (SPI1->DR & 0x00ff);
GPIOA->ODR |= (0x0002);
return(a);
}
//--------------------------------------------------------------------
void DAC(uint16_t d){
uint16_t s;
s = (1<<12) | (d&0x0fff); //Gain=2, Shutdown=0 // 0001(d)
GPIOA->ODR &= ~(0x0008); // 0 kardan ss
SPI1->DR = ((s>>8)&0xff); // 4 bit ersal moshvad
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR =(s&0xff); // 8 bit ersal
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR; // baray etmanan
GPIOA->ODR |= (0x0008); // 1 kardan ss
}
//----------------------------------------------------------------------
uint16_t RamReader(void){

uint16_t r;
// REQUUEST ---------------------------------------------------------
GPIOB->ODR &= ~(0x0010); // b4 ss sram
SPI1->DR = 0x03; //READ instruction
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR; // baray ok shodan flag

SPI1->DR = ((address>>8) & 0xff); //Address(first 8 bits)
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR;
SPI1->DR = (address & 0xff); //Address(last 8 bits)
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);

//---------------------------------------------------------------------

//RECIEVE --------------------------------------------------------------
SPI1->DR;
SPI1->DR = 0x00;
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
r = (SPI1->DR)<<4; // 8 BIT vasn bala
SPI1->DR = 0x00;
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
r |= (SPI1->DR)>>4;
GPIOB->ODR |= (0x0010); // 4 bit vazn paeen
address = address + 2; // chon har seri 2 address pish mire
if(address>=2*SampleNumber){ // age be enteha reside bod az aavla
address = 0;
}
return®;
}
//-------------------------------------------------------------------------------
void RamWriter(uint16_t d){
//REQUEST-------------------------------------------------------------
GPIOB->ODR &= ~(0x0010);//This line sets the Chip Select (CS) pin of the SRAM low
SPI1->DR = 0x02; //WRITE request to SRAM
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR;
SPI1->DR = ((address>>8) & 0xff); //Address(first 8 bits)
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR;
SPI1->DR = (address & 0xff); //Address(last 8 bits)
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
//This block of code sends the address where data will be written to the SRAM.
//-------------------------------------------------------------------
//SEND ---------------------------------------------------------------
SPI1->DR;
SPI1->DR = ((d>>4) & 0xff);
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR;
SPI1->DR = ((d&0xf)<<4);
while((SPI1->SR & SPI_SR_BSY) == SPI_SR_BSY);
SPI1->DR;
GPIOB->ODR |= (0x0010);
address = address + 2;
}
//------------------------------------------------------------------------
